<?php require __DIR__.'/../includes/bootstrap.php';if(!brands_schema_ready()){$brands=[];}else{$q=trim($_GET['q']??'');$sql="SELECT b.*,c.name company_name FROM brands b JOIN companies c ON c.id=b.company_id WHERE b.status='approved'";$args=[];if($q!==''){$sql.=' AND (b.name LIKE ? OR b.category LIKE ? OR c.name LIKE ?)';$args=array_fill(0,3,'%'.$q.'%');}$sql.=' ORDER BY b.name';$s=db()->prepare($sql);$s->execute($args);$brands=$s->fetchAll();}app_header('Brands');?><section class="dashboard-hero"><p class="eyebrow">THE MULTIVERSE</p><h1>Brands</h1><p>Explore approved brands and the companies behind them.</p></section><form class="app-card search-bar"><input name="q" value="<?=e($_GET['q']??'')?>" placeholder="Search brands or companies"><button class="button primary">Search</button><?php if(user()&&brands_schema_ready()):?><a class="button ghost" href="create.php">Create Brand</a><?php endif?></form><section class="company-directory"><?php foreach($brands as $b):?><article class="app-card company-card"><?php if($b['logo_path']):?><img src="<?=e(base_url($b['logo_path']))?>" alt=""><?php endif?><p class="eyebrow"><?=e($b['company_name'])?></p><h2><?=e($b['name'])?></h2><p><?=e($b['short_description'])?></p><a class="button ghost" href="view.php?slug=<?=urlencode($b['slug'])?>">View Brand</a></article><?php endforeach?><?php if(!$brands):?><article class="app-card"><h2>No brands found</h2><p>Approved brands will appear here.</p></article><?php endif?></section><?php app_footer();
